var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"윽, 술 냄새……!","JPN":"うっ、酒臭い……！","ENG":"Ugh, you reek of alcohol...!","TWN":"呃，酒味……！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신, 설마 아직도 술 못 끊은 거야?","JPN":"あんた、まさかまだ酒をやめてなかったのか？","ENG":"Oi, you still haven't managed to kick your drinking habit, have you?","TWN":"你難道還沒戒酒嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"나 참. 하늘에 있는 엄마가 참도 좋아라 하겠네.","JPN":"ったく。天国のお母さんも喜んでるだろうよ。","ENG":"Blimey. Mum must be so happy watching over you in heaven.","TWN":"真是……媽媽在天上知道了，你覺得她會開心嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"집안 꼴은 또 이게 뭐야? 완전 쓰레기 장이 따로 없구만.","JPN":"家の中もめちゃくちゃだな。これじゃ、ゴミ屋敷だ。","ENG":"This place is a dump! Look at all this mess!","TWN":"家裡怎麼這麼髒？簡直就是垃圾場啊。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"비켜 봐, 청소부터…….","JPN":"どけよ、まずは掃除から……","ENG":"Move outta my way so I can start cleaning–","TWN":"讓開，先讓我打掃一下……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐, 이건?","JPN":"待て、これは？","ENG":"Hang on, what's this?","TWN":"等一下，這是？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"허! 이젠 하다하다 약까지 손대는 거야?","JPN":"は！　ついには薬にまで手を出したのか？","ENG":"*Scoff!* You're doing drugs now, too?","TWN":"嘖！你現在連毒品都敢碰了嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신이 글러먹은 인간이라는 건, 꼬맹이 시절부터 알고 있었어.","JPN":"あんたがダメ人間ってことは、ガキの頃からわかってたさ。","ENG":"Since I was a kid, I always knew that you were a piece of trash.","TWN":"你這個人有多麼糟糕，其實我從小就知道。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래도 지금까지 매달 꼬박꼬박 이 집에 돈을 부쳤던 건, 엄마가 남긴 유언 때문이야.","JPN":"でも今まで毎月真面目にこの家に仕送りしてたのは、お母さんの遺言のがあったからだ。","ENG":"The only reason why I'm sending you money every month is because of mum's will.","TWN":"我之所以每個月都按時給家裡寄錢一直到現在，都是因為媽媽留下的遺言。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신을 용서하라고. 당신을 부탁한다고…….","JPN":"あんたを許せって、あんたを頼むって……","ENG":"She asked me to forgive you and take care of you...","TWN":"她要我原諒你，把你交給了我……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"대답해! 이 망할 아버지!","JPN":"答えろ！　このクソ親父！","ENG":"Answer me, you deadbeat dad!","TWN":"回答我！糟糕的爸爸！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"지금까지 내가 준 돈으로 이딴 개짓거리를 하고 있었던 거야?","JPN":"今まで俺が渡した金で、こんなことしてたのか？","ENG":"Is this what you were doing with the money I've been sending you?","TWN":"一直以來，你就是用我給你的錢做了這些蠢事？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"……콜록, 콜록!","JPN":"……ゲホッ、ゲホッ！","ENG":"...*Cough, Cough!*","TWN":"……咳咳，咳咳！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"크흠, 못 본 사이에 꽤 유명해졌더구나. 로이.","JPN":"ゴホッ、ちょっと見ない間に有名になったじゃないか。ロイ。","ENG":"Errhm, you've become quite famous, haven't you, Roy?","TWN":"咳，好久不見，你變得很出名呢，羅伊。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"그래서…… 기관은 때려치고 건틀렛 선수로 살아갈 생각이냐?","JPN":"で……機関はやめてガントレット選手として生きていくつもりか？","ENG":"So... are you thinking of quitting the Institution and becoming a Gauntlet player?","TWN":"所以……你打算離開機關，繼續當聖鎧選手嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"크큭, 그것도 좋겠지. 네놈한테는 길거리 패싸움 수준이 딱 어울리니까 말이야.","JPN":"くくっ、それもいいだろう。お前には道端のケンカがよく似合う。","ENG":"Keke... That's not that bad. Street fights are your thing.","TWN":"呵呵，那也不錯。你這傢伙也就適合在街頭打群架。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"콜록, 콜록! 네놈한테…… <color=#ffd34c>프리드웬</color>은 어울리지 않아.","JPN":"ゲホッ、ゲホッ！　お前に……<color=#ffd34c>プリドウェン</color>は似合わない。","ENG":"*Cough!* *Cough!* <color=#ffd34c>Prydwen</color> isn't a place... for a bloke like you anyway.","TWN":"咳咳，咳咳！你這傢伙……根本配不上<color=#ffd34c>普利多溫</color>。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"그걸 이어받을 자격 같은 건…….","JPN":"あれを受け継ぐ資格なんて……","ENG":"You're not qualified to take over–","TWN":"你沒有接手的資格……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄러워! 무슨 헛소리를 하는 거야?","JPN":"うるさい！　何をわけのわからないこと言ってるんだ？","ENG":"Shut it! What the hell do you think you're doing?!","TWN":"吵死了！你在胡說八道什麼？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"이제와서 부모 노릇이라도 할 셈이야? 내가 뭘 하든 당신이 무슨 상관인데?","JPN":"今さら父親ヅラでもするつもりか？　俺が何をしようと、あんたには関係ないだろ！","ENG":"Think you can parent me now? Why do you care what I do, huh?","TWN":"你現在才想用父親的角色教訓我嗎？我做什麼關你什麼事？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"그래, 다 집어치워.","JPN":"もういい。","ENG":"Yeah, forget about it.","TWN":"算了，別說廢話了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"난 당신이랑 말 싸움이나 하려고 온 게 아니니까.","JPN":"俺はあんたと喧嘩しに来たわけじゃないんだ。","ENG":"I didn't come here to pick a fight with you.","TWN":"我來這裡不是為了跟你吵架。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"내가 묻고 싶은 건 하나뿐이야.","JPN":"俺が聞きたいのは一つだけ。","ENG":"I just want to ask you one question.","TWN":"我只想問你一個問題。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"당신도 한때 프리드웬의 <color=#ffd34c>기관원</color>이었다고 들었어.","JPN":"あんたも一時はプリドウェンの<color=#ffd34c>機関員</color>だったって聞いた。","ENG":"I heard you were also a <color=#ffd34c>member</color> of Prydwen.","TWN":"我聽說你曾經也是普利多溫的<color=#ffd34c>機關成員</color>吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROBERT_PRYDWEN_NPC_NULL","text":{"KOREA":"새디어스인가. 쓸데없는 소리를…….","JPN":"タデウスか。余計なことを……","ENG":"Did Thaddeus say that? That prick...","TWN":"是薩迪烏斯告訴你的？說這些廢話做什麼……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};